// networkModule.js
// React Native Networking Module for API and IoT Device Communication

const API_BASE_URL = 'https://api.example.com';
const DEFAULT_TIMEOUT = 10000;
const IOT_TIMEOUT = 5000;

// Token storage (in production, use SecureStore or similar)
let authToken = null;

const setAuthToken = (token) => {
  authToken = token;
};

const clearAuthToken = () => {
  authToken = null;
};

// Helper: Build headers for API requests
const buildAPIHeaders = (customHeaders = {}) => {
  const headers = {
    'Content-Type': 'application/json',
    'Accept': 'application/json',
    'X-Client-Platform': 'react-native',
    'X-API-Version': 'v1',
    ...customHeaders,
  };

  if (authToken) {
    headers['Authorization'] = `Bearer ${authToken}`;
  }

  return headers;
};

// Helper: Build headers for IoT device requests
const buildIoTHeaders = (customHeaders = {}) => {
  return {
    'Content-Type': 'application/json',
    'Accept': 'application/json',
    'X-Client': 'react-native-controller',
    ...customHeaders,
  };
};

// Helper: Fetch with timeout support
const fetchWithTimeout = (url, options = {}, timeout = DEFAULT_TIMEOUT) => {
  return new Promise((resolve, reject) => {
    const controller = new AbortController();
    const { signal } = controller;

    const timeoutId = setTimeout(() => {
      controller.abort();
      reject(new NetworkError(`Request timed out after ${timeout}ms`, 'TIMEOUT', url));
    }, timeout);

    fetch(url, { ...options, signal })
      .then((response) => {
        clearTimeout(timeoutId);
        resolve(response);
      })
      .catch((error) => {
        clearTimeout(timeoutId);
        if (error.name === 'AbortError') {
          reject(new NetworkError(`Request aborted: ${url}`, 'ABORT', url));
        } else {
          reject(new NetworkError(error.message, 'NETWORK_ERROR', url));
        }
      });
  });
};

// Custom error class for network errors
class NetworkError extends Error {
  constructor(message, code, url, statusCode = null, responseBody = null) {
    super(message);
    this.name = 'NetworkError';
    this.code = code;
    this.url = url;
    this.statusCode = statusCode;
    this.responseBody = responseBody;
  }
}

// Helper: Parse response based on content type
const parseResponse = async (response) => {
  const contentType = response.headers.get('content-type') || '';

  if (contentType.includes('application/json')) {
    return response.json();
  } else if (contentType.includes('text/')) {
    return response.text();
  } else if (contentType.includes('application/octet-stream')) {
    return response.blob();
  }

  // Default: try JSON, fallback to text
  try {
    return await response.json();
  } catch {
    return response.text();
  }
};

// Helper: Process response and handle errors
const processResponse = async (response, url) => {
  if (response.ok) {
    const data = await parseResponse(response);
    return {
      success: true,
      status: response.status,
      headers: response.headers,
      data,
    };
  }

  let errorBody = null;
  try {
    errorBody = await parseResponse(response);
  } catch {
    errorBody = null;
  }

  throw new NetworkError(
    `HTTP ${response.status}: ${response.statusText}`,
    'HTTP_ERROR',
    url,
    response.status,
    errorBody
  );
};

// Retry logic with exponential backoff
const retryRequest = async (requestFn, maxRetries = 3, baseDelay = 1000) => {
  let lastError;

  for (let attempt = 0; attempt <= maxRetries; attempt++) {
    try {
      return await requestFn();
    } catch (error) {
      lastError = error;

      // Don't retry on client errors (4xx) except 408 (Request Timeout) and 429 (Too Many Requests)
      if (
        error.statusCode &&
        error.statusCode >= 400 &&
        error.statusCode < 500 &&
        error.statusCode !== 408 &&
        error.statusCode !== 429
      ) {
        throw error;
      }

      if (attempt < maxRetries) {
        const delay = baseDelay * Math.pow(2, attempt) + Math.random() * 500;
        await new Promise((resolve) => setTimeout(resolve, delay));
        console.log(`Retrying request (attempt ${attempt + 1}/${maxRetries})...`);
      }
    }
  }

  throw lastError;
};

// ==========================================
// API Client - For https://api.example.com
// ==========================================

const apiClient = {
  request: async (method, endpoint, { body, headers, query, timeout, retry } = {}) => {
    let url = `${API_BASE_URL}${endpoint}`;

    // Append query parameters
    if (query && Object.keys(query).length > 0) {
      const queryString = Object.entries(query)
        .filter(([, value]) => value !== null && value !== undefined)
        .map(([key, value]) => `${encodeURIComponent(key)}=${encodeURIComponent(value)}`)
        .join('&');
      url += `?${queryString}`;
    }

    const options = {
      method: method.toUpperCase(),
      headers: buildAPIHeaders(headers),
    };

    if (body && !['GET', 'HEAD'].includes(options.method)) {
      options.body = JSON.stringify(body);
    }

    const requestFn = async () => {
      const response = await fetchWithTimeout(url, options, timeout || DEFAULT_TIMEOUT);
      return processResponse(response, url);
    };

    if (retry !== false) {
      return retryRequest(requestFn, retry?.maxRetries || 2, retry?.baseDelay || 1000);
    }

    return requestFn();
  },

  get: (endpoint, options = {}) => {
    return apiClient.request('GET', endpoint, options);
  },

  post: (endpoint, body, options = {}) => {
    return apiClient.request('POST', endpoint, { ...options, body });
  },

  put: (endpoint, body, options = {}) => {
    return apiClient.request('PUT', endpoint, { ...options, body });
  },

  patch: (endpoint, body, options = {}) => {
    return apiClient.request('PATCH', endpoint, { ...options, body });
  },

  delete: (endpoint, options = {}) => {
    return apiClient.request('DELETE', endpoint, options);
  },

  // Upload file to API
  upload: async (endpoint, fileUri, fieldName = 'file', additionalFields = {}, headers = {}) => {
    const url = `${API_BASE_URL}${endpoint}`;
    const formData = new FormData();

    // Determine file type from URI
    const uriParts = fileUri.split('.');
    const fileExtension = uriParts[uriParts.length - 1];
    const mimeTypes = {
      jpg: 'image/jpeg',
      jpeg: 'image/jpeg',
      png: 'image/png',
      gif: 'image/gif',
      mp4: 'video/mp4',
      pdf: 'application/pdf',
      bin: 'application/octet-stream',
    };

    formData.append(fieldName, {
      uri: fileUri,
      type: mimeTypes[fileExtension.toLowerCase()] || 'application/octet-stream',
      name: `upload.${fileExtension}`,
    });

    // Add additional form fields
    Object.entries(additionalFields).forEach(([key, value]) => {
      formData.append(key, value);
    });

    const uploadHeaders = {
      'Accept': 'application/json',
      ...headers,
    };

    if (authToken) {
      uploadHeaders['Authorization'] = `Bearer ${authToken}`;
    }

    // Note: Don't set Content-Type for FormData; fetch will set it with boundary
    const response = await fetchWithTimeout(
      url,
      {
        method: 'POST',
        headers: uploadHeaders,
        body: formData,
      },
      60000 // 60 second timeout for uploads
    );

    return processResponse(response, url);
  },
};

