const iotClient = {
  // Validate and build IoT device URL
  buildDeviceUrl: (deviceIp, endpoint = '', protocol = 'http', port = null) => {
    // Validate IP format (basic check for 192.168.x.x pattern or any local IP)
    const ipRegex = /^(\d{1,3}\.){3}\d{1,3}$/;
    if (!ipRegex.test(deviceIp)) {
      throw new NetworkError(`Invalid device IP address: ${deviceIp}`, 'INVALID_IP', deviceIp);
    }

    let url = `${protocol}://${deviceIp}`;
    if (port) {
      url += `:${port}`;
    }
    if (endpoint) {
      url += endpoint.startsWith('/') ? endpoint : `/${endpoint}`;
    }
    return url;
  },

  request: async (
    method,
    deviceIp,
    endpoint = '',
    { body, headers, protocol = 'http', port = null, timeout, retry } = {}
  ) => {
    const url = iotClient.buildDeviceUrl(deviceIp, endpoint, protocol, port);

    const options = {
      method: method.toUpperCase(),
      headers: buildIoTHeaders(headers),
    };

    if (body && !['GET', 'HEAD'].includes(options.method)) {
      options.body = JSON.stringify(body);
    }

    const requestFn = async () => {
      const response = await fetchWithTimeout(url, options, timeout || IOT_TIMEOUT);
      return processResponse(response, url);
    };

    if (retry !== false) {
      return retryRequest(requestFn, retry?.maxRetries || 1, retry?.baseDelay || 500);
    }

    return requestFn();
  },

  get: (deviceIp, endpoint, options = {}) => {
    return iotClient.request('GET', deviceIp, endpoint, options);
  },

  post: (deviceIp, endpoint, body, options = {}) => {
    return iotClient.request('POST', deviceIp, endpoint, { ...options, body });
  },

  put: (deviceIp, endpoint, body, options = {}) => {
    return iotClient.request('PUT', deviceIp, endpoint, { ...options, body });
  },

  delete: (deviceIp, endpoint, options = {}) => {
    return iotClient.request('DELETE', deviceIp, endpoint, options);
  },

  // Discover IoT devices on the local network by scanning IP range
  discoverDevices: async (
    subnet = '192.168.1',
    startRange = 1,
    endRange = 254,
    endpoint = '/info',
    port = null,
    protocol = 'http',
    concurrency = 20
  ) => {
    const discoveredDevices = [];
    const ips = [];

    for (let i = startRange; i <= endRange; i++) {
      ips.push(`${subnet}.${i}`);
    }

    // Process in batches to avoid overwhelming the network
    for (let i = 0; i < ips.length; i += concurrency) {
      const batch = ips.slice(i, i + concurrency);
      const promises = batch.map(async (ip) => {
        try {
          const result = await iotClient.get(ip, endpoint, {
            protocol,
            port,
            timeout: 2000,
            retry: false,
          });
          return { ip, ...result.data };
        } catch {
          return null;
        }
      });

      const results = await Promise.all(promises);
      results.forEach((result) => {
        if (result) {
          discoveredDevices.push(result);
        }
      });
    }

    return discoveredDevices;
  },

  // Send firmware update to IoT device
  sendFirmwareUpdate: async (deviceIp, firmwareUri, options = {}) => {
    const { protocol = 'http', port = null, onProgress } = options;
    const url = iotClient.buildDeviceUrl(deviceIp, '/firmware/update', protocol, port);

    const formData = new FormData();
    formData.append('firmware', {
      uri: firmwareUri,
      type: 'application/octet-stream',
      name: 'firmware.bin',
    });

    const fetchOptions = {
      method: 'POST',
      headers: buildIoTHeaders({ 'Content-Type': undefined }), // Let fetch set boundary
      body: formData,
    };

    // Remove Content-Type to let FormData set it
    delete fetchOptions.headers['Content-Type'];

    const response = await fetchWithTimeout(url, fetchOptions, 120000); // 2 min timeout for firmware

    return processResponse(response, url);
  },

  // Ping device to check if it's reachable
  ping: async (deviceIp, protocol = 'http', port = null) => {
    try {
      const startTime = Date.now();
      await iotClient.get(deviceIp, '/ping', {
        protocol,
        port,
        timeout: 3000,
        retry: false,
      });
      const latency = Date.now() - startTime;
      return { reachable: true, latency, ip: deviceIp };
    } catch {
      return { reachable: false, latency: null, ip: deviceIp };
    }
  },

  // Batch command to multiple devices
  broadcastCommand: async (deviceIps, endpoint, body, options = {}) => {
    const results = await Promise.allSettled(
      deviceIps.map((ip) =>
        iotClient.post(ip, endpoint, body, { ...options, retry: false }).then((result) => ({
          ip,
          success: true,
          data: result.data,
        }))
      )
    );

    return results.map((result, index) => {
      if (result.status === 'fulfilled') {
        return result.value;
      }
      return {
        ip: deviceIps[index],
        success: false,
        error: result.reason.message,
      };
    });
  },
};

