// ==========================================
// Request queue for offline support
// ==========================================

class RequestQueue {
  constructor() {
    this.queue = [];
    this.processing = false;
  }

  enqueue(requestFn, metadata = {}) {
    return new Promise((resolve, reject) => {
      this.queue.push({
        requestFn,
        resolve,
        reject,
        metadata,
        timestamp: Date.now(),
      });
    });
  }

  async processQueue() {
    if (this.processing || this.queue.length === 0) {
      return;
    }

    this.processing = true;

    while (this.queue.length > 0) {
      const item = this.queue.shift();

      // Skip items older than 5 minutes
      if (Date.now() - item.timestamp > 300000) {
        item.reject(new NetworkError('Request expired in queue', 'QUEUE_EXPIRED', ''));
        continue;
      }

      try {
        const result = await item.requestFn();
        item.resolve(result);
      } catch (error) {
        // If still a network error, re-enqueue
        if (error.code === 'NETWORK_ERROR' || error.code === 'TIMEOUT') {
          this.queue.unshift(item);
          break;
        }
        item.reject(error);
      }
    }

    this.processing = false;
  }

  getQueueLength() {
    return this.queue.length;
  }

  clearQueue() {
    const cleared = this.queue.length;
    this.queue.forEach((item) => {
      item.reject(new NetworkError('Queue cleared', 'QUEUE_CLEARED', ''));
    });
    this.queue = [];
    return cleared;
  }
}

